/*
 * PHASE-07B FROZEN TURN EXTENSION INTERFACE
 *
 * A turn always resolves in this order:
 * 1. the player action resolves through built-in handling or the action-resolver
 *    registry;
 * 2. every other actor runs exactly once in stable actor-id order;
 * 3. end-of-turn tick hooks run in this fixed order:
 *    damageOverTime -> durations -> hunger -> regen.
 *
 * Frozen extension surface:
 * - registerActionResolver handles move/attack/use_item/pickup/talk/inspect.
 * - TurnHooks.actorTurn handles non-player actors in stable actor-id order.
 * - TurnHooks.ticks handles fixed-order end-of-turn systems.
 *
 * Do not rename action kinds or TickHookName values, reorder TICK_HOOK_ORDER, or
 * let resolvers/hooks call ambient nondeterminism or LLMs. Resolvers and hooks
 * must return deterministic state/events.
 */

import { bounds, config, type GameConfig } from "../../config/index.js";
import { createClock } from "../clock/index.js";
import {
  ACTIVE_TERMINAL_STATUS,
  createInitialState,
  type EngineLogEvent,
  type EntityId,
  type EntityInstance,
  type GameState,
  type TerminalStatus,
} from "../state/index.js";
import {
  checkActionLegality,
  type PlayerAction,
} from "./actions.js";

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly action_illegal: {
      readonly actionKind: PlayerAction["kind"];
      readonly reason: string;
    };
    readonly action_resolved: {
      readonly actionKind: PlayerAction["kind"];
    };
    readonly actor_turn: {
      readonly actorId: EntityId;
    };
    readonly tick_hook: {
      readonly hook: TickHookName;
    };
    readonly terminal_state: {
      readonly status: Exclude<TerminalStatus, "ACTIVE">;
      readonly reason: string;
    };
  }
}

export { checkActionLegality, getAvailableActions } from "./actions.js";
export type {
  AbortAction,
  ActionLegality,
  ActionTarget,
  AttackAction,
  DescendAction,
  InspectAction,
  MoveAction,
  MoveDirection,
  PickupAction,
  PlayerAction,
  TalkAction,
  UseItemAction,
  WaitAction,
} from "./actions.js";

export type TurnEvent = EngineLogEvent;

export type ActorEntity = Extract<EntityInstance, { readonly kind: "enemy" | "npc" }>;

export type ActionResolverActionKind =
  | "move"
  | "attack"
  | "use_item"
  | "pickup"
  | "talk"
  | "inspect";

export type ActionResolverAction = Extract<
  PlayerAction,
  { readonly kind: ActionResolverActionKind }
>;

export type ActionResolverSuccess = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type ActionResolverIllegal = {
  readonly illegal: true;
  readonly reason: string;
};

export type ActionResolverResult =
  | ActionResolverSuccess
  | ActionResolverIllegal;

export type ActionResolver<
  Action extends ActionResolverAction = ActionResolverAction,
> = (state: GameState, action: Action) => ActionResolverResult;

export type TickHookName =
  | "damageOverTime"
  | "durations"
  | "hunger"
  | "regen";

export const TICK_HOOK_ORDER = [
  "damageOverTime",
  "durations",
  "hunger",
  "regen",
] as const satisfies readonly TickHookName[];

export type TurnHookResult =
  | GameState
  | {
      readonly state: GameState;
      readonly events?: readonly TurnEvent[];
    };

export type ActorTurnHook = (context: {
  readonly state: GameState;
  readonly actor: ActorEntity;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHook = (context: {
  readonly state: GameState;
  readonly hook: TickHookName;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHooks = {
  readonly [Hook in TickHookName]: TickHook;
};

export type TurnHooks = {
  readonly actorTurn?: ActorTurnHook;
  readonly ticks?: Partial<TickHooks>;
};

export type ResolvedTurnHooks = {
  readonly actorTurn: ActorTurnHook;
  readonly ticks: TickHooks;
};

export type StepOptions = {
  readonly hooks?: TurnHooks;
};

export type StepResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type StartContent = {
  readonly config?: GameConfig;
};

const actionResolvers = new Map<ActionResolverActionKind, ActionResolver>();

export const registerActionResolver = <
  Kind extends ActionResolverActionKind,
>(
  actionType: Kind,
  resolver: ActionResolver<Extract<PlayerAction, { readonly kind: Kind }>>,
): (() => void) => {
  const previous = actionResolvers.get(actionType);
  const registeredResolver = resolver as ActionResolver;
  actionResolvers.set(actionType, registeredResolver);

  return () => {
    if (actionResolvers.get(actionType) !== registeredResolver) {
      return;
    }

    if (previous === undefined) {
      actionResolvers.delete(actionType);
      return;
    }

    actionResolvers.set(actionType, previous);
  };
};

export const start = (seed: string, content: StartContent = {}): GameState =>
  createInitialState(seed, content.config ?? config);

export const step = (
  state: GameState,
  action: PlayerAction,
  options: StepOptions = {},
): StepResult => {
  if (isTerminal(state)) {
    return illegalStep(
      state,
      action,
      `run is terminal (${state.run.terminalStatus})`,
    );
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return illegalStep(state, action, legality.reason);
  }

  const forcedTerminal = forcedTerminalFor(state);
  if (forcedTerminal !== null) {
    return terminalStep(state, forcedTerminal.status, forcedTerminal.reason);
  }

  }

  const hooks = resolveTurnHooks(options.hooks);
  const playerActionResult = applyPlayerAction(state, action);
  if (isActionResolverIllegal(playerActionResult)) {
    return illegalStep(state, action, playerActionResult.reason);
  }

  const events: TurnEvent[] = [
    turnEvent(state.run.turn, "action_resolved", {
      actionKind: action.kind,
    }),
    ...playerActionResult.events,
  ];

  let nextState = playerActionResult.state;

  if (!isTerminal(nextState)) {
    for (const actor of actorsInTurnOrder(nextState)) {
      events.push(
        turnEvent(nextState.run.turn, "actor_turn", {
          actorId: actor.id,
        }),
      );

      const result = normalizeHookResult(
        hooks.actorTurn({
          state: nextState,
          actor,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    for (const hook of TICK_HOOK_ORDER) {
      events.push(
        turnEvent(nextState.run.turn, "tick_hook", {
          hook,
        }),
      );

      const result = normalizeHookResult(
        hooks.ticks[hook]({
          state: nextState,
          hook,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    nextState = advanceTurn(nextState);

    const terminal = forcedTerminalFor(nextState);
    if (terminal !== null) {
      nextState = withTerminalStatus(nextState, terminal.status);
      events.push(
        turnEvent(nextState.run.turn, "terminal_state", {
          status: terminal.status,
          reason: terminal.reason,
        }),
      );
    }
  }

  nextState = appendLog(nextState, events);

  return {
    state: nextState,
    events,
  };
};

export const render = (state: GameState): string =>
  [
    `run=${state.run.runId}`,
    `turn=${state.run.turn}`,
    `depth=${state.run.depth}`,
    `status=${state.run.terminalStatus}`,
    `player=(${state.player.position.x},${state.player.position.y})`,
    `hp=${state.player.hp.current}/${state.player.hp.max}`,
  ].join(" ");

export const isTerminal = (state: GameState): boolean =>
  state.run.terminalStatus !== ACTIVE_TERMINAL_STATUS;

export const createNoopTurnHooks = (): ResolvedTurnHooks => ({
  actorTurn: ({ state }) => state,
  ticks: {
    damageOverTime: ({ state }) => state,
    durations: ({ state }) => state,
    hunger: ({ state }) => state,
    regen: ({ state }) => state,
  },
});

const applyPlayerAction = (
  state: GameState,
  action: PlayerAction,
): ActionResolverResult => {
  if (action.kind === "abort") {
    const status = config.runStructure.terminalStates.abort;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player aborted the run",
        }),
      ],
    };
  }

  if (
    action.kind === "descend" &&
    state.run.depth >= config.runStructure.depthFloors
  ) {
    const status = config.runStructure.terminalStates.win;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player descended from the final floor",
        }),
      ],
    };
  }

  if (action.kind === "wait") {
    return {
      state,
      events: [],
    };
  }

  if (isActionResolverAction(action)) {
    return applyRegisteredActionResolver(state, action);
  }

  return {
    state,
    events: [],
  };
};

const applyRegisteredActionResolver = (
  state: GameState,
  action: ActionResolverAction,
): ActionResolverResult => {
  const resolver = actionResolvers.get(action.kind);

  if (resolver === undefined) {
    return {
      illegal: true,
      reason: "no handler registered",
    };
  }

  return resolver(state, action);
};

const isActionResolverAction = (
  action: PlayerAction,
): action is ActionResolverAction => {
  switch (action.kind) {
    case "move":
    case "attack":
    case "use_item":
    case "pickup":
    case "talk":
    case "inspect":
      return true;
    case "wait":
    case "descend":
    case "abort":
      return false;
  }
};

const isActionResolverIllegal = (
  result: ActionResolverResult,
): result is ActionResolverIllegal => "illegal" in result;

const forcedTerminalFor = (
  state: GameState,
): { readonly status: Exclude<TerminalStatus, "ACTIVE">; readonly reason: string } | null => {
  if (state.player.hp.current <= 0) {
    return {
      status: config.runStructure.terminalStates.loss,
      reason: "player HP reached 0",
    };
  }

  if (state.run.turn >= bounds.runStructure.perRunHardCapTurns) {
    return {
      status: config.runStructure.terminalStates.loss,
      reason: `run hard cap reached at ${bounds.runStructure.perRunHardCapTurns} turns`,
    };
  }

  return null;
};

const terminalStep = (
  state: GameState,
  status: Exclude<TerminalStatus, "ACTIVE">,
  reason: string,
): StepResult => {
  const event = turnEvent(state.run.turn, "terminal_state", {
    status,
    reason,
  });
  const terminalState = appendLog(withTerminalStatus(state, status), [event]);

  return {
    state: terminalState,
    events: [event],
  };
};

const illegalStep = (
  state: GameState,
  action: PlayerAction,
  reason: string,
): StepResult => ({
  state,
  events: [
    turnEvent(state.run.turn, "action_illegal", {
      actionKind: action.kind,
      reason,
    }),
  ],
});

const resolveTurnHooks = (hooks: TurnHooks | undefined): ResolvedTurnHooks => {
  const noopHooks = createNoopTurnHooks();

  return {
    actorTurn: hooks?.actorTurn ?? noopHooks.actorTurn,
    ticks: {
      ...noopHooks.ticks,
      ...hooks?.ticks,
    },
  };
};

const normalizeHookResult = (
  result: TurnHookResult,
): { readonly state: GameState; readonly events: readonly TurnEvent[] } => {
  if (isHookResultEnvelope(result)) {
    return {
      state: result.state,
      events: result.events ?? [],
    };
  }

  return {
    state: result,
    events: [],
  };
};

const isHookResultEnvelope = (
  result: TurnHookResult,
): result is Extract<TurnHookResult, { readonly state: GameState }> =>
  "state" in result;

const actorsInTurnOrder = (state: GameState): readonly ActorEntity[] =>
  Object.values(state.entities)
    .filter(isActorEntity)
    .sort((a, b) => compareEntityIds(a.id, b.id));

const isActorEntity = (entity: EntityInstance): entity is ActorEntity =>
  entity.kind === "enemy" || entity.kind === "npc";

const compareEntityIds = (a: EntityId, b: EntityId): number => {
  const parsedA = parseEntityId(a);
  const parsedB = parseEntityId(b);
  const kindOrder = parsedA.kind.localeCompare(parsedB.kind);

  return kindOrder === 0 ? parsedA.index - parsedB.index : kindOrder;

export * from "./init.js";
export * from "./serialize.js";
export * from "./types.js";

export const Terrain = {
  Floor: "floor",
  Wall: "wall",
  Door: "door",
  Water: "water",
  StairsDown: "stairs_down",
  Entrance: "entrance",
} as const;

export type TerrainKind = (typeof Terrain)[keyof typeof Terrain];

export type DoorState = "open" | "closed";

export type Tile = {
  readonly terrain: TerrainKind;
  readonly door: DoorState | null;
};

export const TERRAIN_KINDS = [
  Terrain.Floor,
  Terrain.Wall,
  Terrain.Door,
  Terrain.Water,
  Terrain.StairsDown,
  Terrain.Entrance,
] as const satisfies readonly TerrainKind[];

export const TERRAIN_WALKABLE = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: true,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const TERRAIN_TRANSPARENT = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: false,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const createTile = (
  terrain: TerrainKind,
  door: DoorState | null = null,
): Tile => ({
  terrain,
  door: terrain === Terrain.Door ? (door ?? "closed") : null,
});

export const cloneTile = (tile: Tile): Tile => ({
  terrain: tile.terrain,
  door: tile.terrain === Terrain.Door ? (tile.door ?? "closed") : null,
});

export const isWalkableTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_WALKABLE[terrain];

export const isTransparentTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_TRANSPARENT[terrain];

export const isWalkableTile = (tile: Tile): boolean =>
  TERRAIN_WALKABLE[tile.terrain];

export const isTransparentTile = (tile: Tile): boolean => {
  if (tile.terrain === Terrain.Door) {
    return tile.door === "open";
  }

  return TERRAIN_TRANSPARENT[tile.terrain];
};

import {
  bounds,
  config as defaultConfig,
  type GameConfig,
} from "../../config/index.js";
import {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import type { DepthBand } from "../../schemas/entities/index.js";
import { createClock } from "../clock/index.js";
import {
  ACTIVE_TERMINAL_STATUS,
  type EntityId,
  type EntityIdCounters,
  type EntityKind,
  type GameState,
  type Position,
} from "./types.js";

export const ROOT_RNG_STREAM_ID = "root" as const;

export const createInitialEntityCounters = (): EntityIdCounters => ({
  enemy: 0,
  npc: 0,
  item: 0,
  trap: 0,
});

export interface EntityIdAllocation {
  readonly id: EntityId;
  readonly entityCounters: EntityIdCounters;
}

export const allocateEntityId = (
  counters: EntityIdCounters,
  kind: EntityKind,
): EntityIdAllocation => {
  const next = counters[kind] + 1;

  return {
    id: `${kind}#${next}` as EntityId,
    entityCounters: {
      ...counters,
      [kind]: next,
    },
  };
};

export const depthBandForDepth = (
  depth: number,
  gameConfig: GameConfig = defaultConfig,
): DepthBand => {
  if (!Number.isSafeInteger(depth)) {
    throw new RangeError("depth must be a safe integer");
  }

  for (const [band, range] of depthBandEntries(gameConfig)) {
    if (depth >= range.minFloor && depth <= range.maxFloor) {
      return band;
    }
  }

  throw new RangeError(`depth ${depth} is outside configured depth bands`);
};

export const createInitialState = (
  seed: string,
  gameConfig: GameConfig = defaultConfig,
): GameState => {
  const turn = createClock().now();
  const depth = initialDepth(gameConfig);
  const band = depthBandForDepth(depth, gameConfig);
  const runId = runIdForSeed(seed);
  const startPosition = unplacedPosition();
  const playerHp = gameConfig.playerCharacter.stats.hp.start;
  const playerFullness = gameConfig.playerCharacter.stats.fullness.start;

  return {
    version: {
      protocolVersion: PROTOCOL_VERSION,
      engineVersion: ENGINE_VERSION,
    },
    run: {
      runId,
      seed,
      depth,
      band,
      turn,
      terminalStatus: ACTIVE_TERMINAL_STATUS,
    },
    floor: {
      floorId: `floor#${depth}`,
      depth,
      band,
      geometry: {
        refId: `floor-geometry#${depth}`,
        opaque: null,
      },
    },
    player: {
      hp: {
        current: playerHp,
        max: playerHp,
      },
      level: gameConfig.playerCharacter.stats.level.start,
      xp: 0,
      fullness: {
        current: playerFullness,
        max: bounds.playerCharacter.fullnessCap,
      },
      position: startPosition,
      inventory: Array.from(
        { length: gameConfig.playerCharacter.inventory.slots },
        () => null,
      ),
      equipment: {
        weapon: null,
        armor: null,
        charms: Array.from(
          { length: gameConfig.playerCharacter.equipmentSlots.charms },
          () => null,
        ),
      },
      statuses: [],
    },
    entities: {},
    quests: {
      quests: {},
      activeQuestIds: [],
      completedQuestIds: [],
      failedQuestIds: [],
    },
    log: [
      {
        turn,
        type: "state_created",
        data: {
          runId,
          seed,
          depth,
          band,
        },
      },
    ],
    rng: {
      rootSeed: seed,
      streams: {
        [ROOT_RNG_STREAM_ID]: {
          streamId: ROOT_RNG_STREAM_ID,
          seed,
          parentStreamId: null,
          draws: 0,
        },
      },
    },
    ids: {
      entityCounters: createInitialEntityCounters(),
    },
  };
};

const runIdForSeed = (seed: string): string => `run#${seed}`;

const unplacedPosition = (): Position => ({
  x: 0,
  y: 0,
});

const initialDepth = (gameConfig: GameConfig): number => {
  const entries = depthBandEntries(gameConfig);
  const firstEntry = entries[0];

  if (firstEntry === undefined) {
    throw new RangeError("config must define at least one depth band");
  }

  let depth = firstEntry[1].minFloor;
  for (const [, range] of entries) {
    if (range.minFloor < depth) {
      depth = range.minFloor;
    }
  }

  return depth;
};

const depthBandEntries = (
  gameConfig: GameConfig,
): readonly [
  DepthBand,
  {
    readonly minFloor: number;
    readonly maxFloor: number;
  },
][] =>
  Object.entries(gameConfig.runStructure.depthBands) as readonly [
    DepthBand,
    {
      readonly minFloor: number;
      readonly maxFloor: number;
    },
  ][];

import type { GameConfig } from "../../config/index.js";
import type {
  DepthBand,
  EnemyDefinition,
  ItemDefinition,
  NpcDefinition,
  QuestDefinition,
  TrapDefinition,
} from "../../schemas/entities/index.js";
import type {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import type { StatusApplication } from "../../schemas/vocab/index.js";

export type SerializablePrimitive = string | number | boolean | null;

export type SerializableValue =
  | SerializablePrimitive
  | readonly SerializableValue[]
  | { readonly [key: string]: SerializableValue };

export type SerializableRecord = {
  readonly [key: string]: SerializableValue;
};

export const ACTIVE_TERMINAL_STATUS = "ACTIVE" as const;

export type ConfiguredTerminalStatus =
  GameConfig["runStructure"]["terminalStates"][keyof GameConfig["runStructure"]["terminalStates"]];

export type TerminalStatus =
  | typeof ACTIVE_TERMINAL_STATUS
  | ConfiguredTerminalStatus;

export interface VersionStamp {
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: typeof ENGINE_VERSION;
}

export interface RunMeta {
  readonly runId: string;
  readonly seed: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly turn: number;
  readonly terminalStatus: TerminalStatus;
}

export interface Position {
  readonly x: number;
  readonly y: number;
}

export interface FloorGeometrySlot {
  readonly refId: string;
  /*
   * PHASE-07A contract: the map module owns this payload's concrete shape.
   * PHASE-06 only requires a stable, serializable geometry reference by id.
   */
  readonly opaque: SerializableRecord | null;
}

export interface FloorState {
  readonly floorId: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly geometry: FloorGeometrySlot;
}

export interface PlayerItemStack {
  readonly itemInstanceId: string;
  readonly definition: ItemDefinition;
  readonly quantity: number;
  readonly identified: boolean;
}

export type InventorySlot = PlayerItemStack | null;

export interface EquipmentState {
  readonly weapon: PlayerItemStack | null;
  readonly armor: PlayerItemStack | null;
  readonly charms: readonly (PlayerItemStack | null)[];
}

export interface PlayerState {
  readonly hp: {
    readonly current: number;
    readonly max: number;
  };
  readonly level: number;
  readonly xp: number;
  readonly fullness: {
    readonly current: number;
    readonly max: number;
  };
  readonly position: Position;
  readonly inventory: readonly InventorySlot[];
  readonly equipment: EquipmentState;
  readonly statuses: readonly StatusApplication[];
}

export type EntityKind = "enemy" | "npc" | "item" | "trap";

export type EntityIdCounters = {
  readonly [Kind in EntityKind]: number;
};

export type EntityId = `${EntityKind}#${number}`;

export interface EntityRuntimeFields {
  readonly id: EntityId;
  readonly position: Position;
  readonly currentHP: number | null;
  readonly statuses: readonly StatusApplication[];
  readonly behaviorRuntime: SerializableRecord;
}

export interface EnemyEntityInstance extends EntityRuntimeFields {
  readonly kind: "enemy";
  readonly definition: EnemyDefinition;
  readonly currentHP: number;
}

export interface NpcEntityInstance extends EntityRuntimeFields {
  readonly kind: "npc";
  readonly definition: NpcDefinition;
  readonly dialogueRuntime: SerializableRecord;
}

export interface GroundItemEntityInstance extends EntityRuntimeFields {
  readonly kind: "item";
  readonly definition: ItemDefinition;
  readonly currentHP: null;
  readonly quantity: number;
  readonly identified: boolean;
}

export interface TrapEntityInstance extends EntityRuntimeFields {
  readonly kind: "trap";
  readonly definition: TrapDefinition;
  readonly currentHP: null;
  readonly armed: boolean;
}

export type EntityInstance =
  | EnemyEntityInstance
  | NpcEntityInstance
  | GroundItemEntityInstance
  | TrapEntityInstance;

export type EntityMap = {
  readonly [id: string]: EntityInstance;
};

export type QuestRuntimeStatus = "available" | "active" | "completed" | "failed";

export interface QuestRuntime {
  readonly definition: QuestDefinition;
  readonly status: QuestRuntimeStatus;
  readonly progress: SerializableRecord;
}

export interface QuestState {
  readonly quests: {
    readonly [id: string]: QuestRuntime;
  };
  readonly activeQuestIds: readonly string[];
  readonly completedQuestIds: readonly string[];
  readonly failedQuestIds: readonly string[];
}

/*
 * Log extension pattern:
 * later engine systems add event types by declaration-merging this interface.
 * The runtime serializer validates the event envelope and serializable data.
 */
export interface EngineLogEventDataByType {
  readonly state_created: {
    readonly runId: string;
    readonly seed: string;
    readonly depth: number;
    readonly band: DepthBand;
  };
  readonly state_serialized: {
    readonly format: "stable-json";
  };
  readonly state_deserialized: {
    readonly format: "stable-json";
  };
}

export type EngineLogEventType = Extract<
  keyof EngineLogEventDataByType,
  string
>;

export type EngineLogEvent = {
  readonly [Type in EngineLogEventType]: {
    readonly turn: number;
    readonly type: Type;
    readonly data: EngineLogEventDataByType[Type];
  };
}[EngineLogEventType];

export interface RngStreamCursor {
  readonly streamId: string;
  readonly seed: string;
  readonly parentStreamId: string | null;
  readonly draws: number;
}

export interface RngState {
