198	const parseMap = (source: string): ParsedMap => {
199	  const rows = source.trim().split("\n");
200	  const width = rows[0]?.length ?? 0;
201	  const tiles: Tile[] = [];
202	  const markerEntries: [string, Position][] = [];
203	
204	  for (let y = 0; y < rows.length; y += 1) {
205	    const row = rows[y];
206	
207	    if (row === undefined || row.length !== width) {
208	      throw new Error("fixture rows must have equal width");
209	    }
210	
211	    for (let x = 0; x < row.length; x += 1) {
212	      const character = row[x];
213	      const position = { x, y };
214	      const tile = tileForCharacter(character);
215	
216	      if (character !== undefined && /[A-Z@]/u.test(character)) {
217	        markerEntries.push([character, position]);
218	      }
219	
220	      tiles.push(tile);
221	    }
222	  }
223	
224	  return {
225	    grid: createTileGrid({ width, height: rows.length, tiles }),
226	    markers: new Map(markerEntries),
227	  };
228	};
