234	    case "+":
235	      return createTile(Terrain.Door, "closed");
236	    case "/":
237	      return createTile(Terrain.Door, "open");
238	    case ">":
239	      return createTile(Terrain.StairsDown);
240	    case ".":

240	    case ".":
241	    case "@":
242	    case "E":
243	    case "N":
244	      return createTile(Terrain.Floor);
245	    default:
246	      throw new Error(`unsupported fixture character ${String(character)}`);
247	  }
248	};
